from dataclasses import dataclass, field


@dataclass
class CompoundGoal:
    """
    A goal decomposed into ordered phases. Each phase has its own
    success criteria. Phases execute sequentially; a phase is not
    started until the previous phase's criteria are met.
    """
    name: str
    phases: list["GoalPhase"]
    current_phase: int = 0

    def active_phase(self) -> "GoalPhase":
        return self.phases[self.current_phase]

    def advance(self) -> bool:
        """Advance to the next phase. Returns False if already at last phase."""
        if self.current_phase < len(self.phases) - 1:
            self.current_phase += 1
            return True
        return False

    def is_complete(self) -> bool:
        return self.current_phase == len(self.phases) - 1

    def to_prompt(self) -> str:
        phase = self.active_phase()
        total = len(self.phases)
        current = self.current_phase + 1
        criteria = "\n".join(f"- {c}" for c in phase.criteria)
        return (
            f"Task (phase {current}/{total}): {phase.task}\n\n"
            f"Done when:\n{criteria}"
        )


@dataclass
class GoalPhase:
    task: str
    criteria: list[str] = field(default_factory=list)


# Example: a three-phase coding task
REFACTOR_GOAL = CompoundGoal(
    name="Refactor auth module",
    phases=[
        GoalPhase(
            task="Read and understand the current auth implementation.",
            criteria=[
                "You have read auth.py, session.py, and middleware.py.",
                "You have identified at least one structural issue to address.",
            ],
        ),
        GoalPhase(
            task="Refactor the auth module to separate token generation from validation.",
            criteria=[
                "auth.py contains a TokenGenerator class with a generate() method.",
                "auth.py contains a TokenValidator class with a validate() method.",
                "pytest tests/test_auth.py exits with code 0.",
            ],
        ),
        GoalPhase(
            task="Update the middleware to use the new classes.",
            criteria=[
                "middleware.py imports TokenValidator, not any generate function.",
                "pytest tests/ exits with code 0.",
            ],
        ),
    ],
)

import anthropic

client = anthropic.Anthropic()


def run_with_goal(goal: AgentGoal, tools: list[dict]) -> str:
    """
    Agent loop driven by a structured goal. The task prompt is in
    messages[0]; the goal's success criteria drive the stop condition.
    """
    messages = [{"role": "user", "content": goal.to_prompt()}]

    for step in range(30):
        response = client.messages.create(
            model="claude-sonnet-4-6",
            max_tokens=4096,
            tools=tools,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": response.content})

        if response.stop_reason == "end_turn":
            # Model says it is done — verify criteria externally if possible
            for block in response.content:
                if hasattr(block, "text"):
                    return block.text
            return ""

        tool_results = []
        for block in response.content:
            if block.type == "tool_use":
                tool_results.append({
                    "type": "tool_result",
                    "tool_use_id": block.id,
                    "content": dispatch_tool(block.name, block.input),
                })
        messages.append({"role": "user", "content": tool_results})

    return "Max steps reached without completing goal."


def dispatch_tool(name: str, input: dict) -> str:
    return f"result of {name}"

import pytest


class TestAgentGoalToPrompt:
    def test_task_present(self):
        g = AgentGoal(task="Fix the bug.", success_criteria=[])
        assert "Fix the bug." in g.to_prompt()

    def test_criteria_present(self):
        g = AgentGoal(
            task="Fix the bug.",
            success_criteria=["Tests pass.", "No new packages."],
        )
        prompt = g.to_prompt()
        assert "Tests pass." in prompt
        assert "No new packages." in prompt

    def test_constraints_labelled(self):
        g = AgentGoal(
            task="Fix the bug.",
            success_criteria=["Tests pass."],
            constraints=["Do not modify tests."],
        )
        prompt = g.to_prompt()
        assert "Out of scope" in prompt
        assert "Do not modify tests." in prompt


class TestCompoundGoal:
    def _make_goal(self):
        return CompoundGoal(
            name="two-phase",
            phases=[
                GoalPhase(task="Phase 1", criteria=["A done."]),
                GoalPhase(task="Phase 2", criteria=["B done."]),
            ],
        )

    def test_starts_at_phase_0(self):
        g = self._make_goal()
        assert g.active_phase().task == "Phase 1"

    def test_advance_moves_to_next(self):
        g = self._make_goal()
        g.advance()
        assert g.active_phase().task == "Phase 2"

    def test_is_complete_at_last_phase(self):
        g = self._make_goal()
        g.advance()
        assert g.is_complete() is True

    def test_prompt_shows_phase_number(self):
        g = self._make_goal()
        prompt = g.to_prompt()
        assert "phase 1/2" in prompt
